try {
  const rawOutput = $('Nanda').first().json.output || $input.first().json.output || $input.first().json.text || '';
  const MIN_DELAY = 1000;
  const MAX_DELAY = 3500;
  const PER_CHAR = 30;
  const text = rawOutput.replace(/\\n/g, '\n').replace(/\r\n/g, '\n');

  function detectFormat(s) {
    const t = s.trim().toLowerCase();
    if (/\.(jpg|jpeg|png|gif|webp)(\?|$)/.test(t)) return 'imagem';
    if (/\.(mp4|avi|mov|webm)(\?|$)/.test(t)) return 'video';
    if (/\.(opus|mp3|wav|ogg|m4a)(\?|$)/.test(t)) return 'audio';
    return 'texto';
  }
  function stripIndicators(s) {
    return s.replace(/\[(Audio|Imagem|Video|PDF|Documento)\]/gi, '').trim();
  }
  function calcDelay(len) {
    return Math.min(MAX_DELAY, Math.max(MIN_DELAY, Math.round(len * PER_CHAR)));
  }

  let cleanText = text;

  const blocoUnicoMap = {};
  let blocoIdx = 0;
  cleanText = cleanText.replace(/"?\[BLOCO_UNICO\]([\s\S]*?)\[\/BLOCO_UNICO\]"?/g, (match, inner) => {
    const placeholder = `__BLOCO_UNICO_${blocoIdx}__`;
    blocoUnicoMap[placeholder] = inner.trim();
    blocoIdx++;
    return placeholder;
  });

  const captionMap = {};
  let captionIdx = 0;
  cleanText = cleanText.replace(/\[CAPTION\]([\s\S]*?)\[\/CAPTION\]/g, (match, inner) => {
    const placeholder = `__CAPTION_${captionIdx}__`;
    captionMap[placeholder] = inner.trim();
    captionIdx++;
    return placeholder;
  });

  let rawParts;
  if (cleanText.includes('---BLOCO---')) {
    const blocos = cleanText.split('---BLOCO---');
    rawParts = [];
    for (const bloco of blocos) {
      const trimmed = bloco.trim();
      if (!trimmed) continue;
      if (trimmed.startsWith('__BLOCO_UNICO_')) {
        rawParts.push(trimmed);
      } else {
        const lines = trimmed.split(/\n+/).map(s => s.trim()).filter(Boolean);
        rawParts.push(...lines);
      }
    }
  } else {
    rawParts = cleanText.split(/\n+/).map(s => s.trim()).filter(Boolean);
  }

  const result = [];
  let i = 0;
  while (i < rawParts.length) {
    const part = rawParts[i];
    if (blocoUnicoMap[part] !== undefined) {
      const conteudo = blocoUnicoMap[part];
      result.push({ json: { conteudo, formato: 'texto', delay: calcDelay(conteudo.length), dinamico: false } });
      i++;
      continue;
    }
    const cleaned = stripIndicators(part);
    if (!cleaned) { i++; continue; }
    if (cleaned.startsWith('[CAPTION]')) {
      const captionText = cleaned.slice('[CAPTION]'.length).trim();
      if (result.length > 0 && result[result.length - 1].json.formato === 'imagem') {
        result[result.length - 1].json.caption = captionText;
      }
      i++;
      continue;
    }
    const formato = cleaned.startsWith('http') ? detectFormat(cleaned) : 'texto';
    if (formato === 'imagem' && i + 1 < rawParts.length) {
      const nextPart = rawParts[i + 1].trim();
      if (captionMap[nextPart] !== undefined) {
        result.push({ json: { conteudo: cleaned, formato: 'imagem', caption: captionMap[nextPart], delay: 5000, dinamico: false } });
        i += 2;
        continue;
      }
    }
    const delay = formato === 'texto' ? calcDelay(cleaned.length) : 5000;
    result.push({ json: { conteudo: cleaned, formato, delay, dinamico: false } });
    i++;
  }

  if (result.length === 0) {
    result.push({ json: { conteudo: rawOutput || 'Opa! Como posso te ajudar? 😊', formato: 'texto', delay: MIN_DELAY, dinamico: false } });
  }
  const vistos = new Set();
  let finalResult = [];
  for (const r of result) {
    const chave = String(r.json.conteudo || '').trim();
    if (chave && vistos.has(chave)) continue;
    if (chave) vistos.add(chave);
    finalResult.push(r);
  }
  const MAX_MSGS = 7;
  if (finalResult.length > MAX_MSGS) finalResult = finalResult.slice(0, MAX_MSGS);
  return finalResult;
} catch(e) {
  return [{ json: { conteudo: 'Erro ao processar resposta', formato: 'texto', delay: 3500, dinamico: false, erro: e.message } }];
}
